import { GoogleGenAI } from "@google/genai";
// Safety check for Webpack environment where process.env might not be polyfilled
let apiKey = '';
if (typeof process !== 'undefined' && process.env && process.env.GEMINI_API_KEY) {
    apiKey = process.env.GEMINI_API_KEY;
}
const ai = new GoogleGenAI({
    apiKey: apiKey
});
const STORY_SYSTEM_PROMPT = `
你是一个带有Meta元素的1-bit黑白风格悬疑爱情RP文字游戏的底层意识交互引擎。请根据玩家的行动和当前状态生成后续发展。文风要求：克制、压抑、充满心理暗示与阈限空间（Liminal Space）的迷失感，聚焦于女主角（容绵）与一个“似乎存在又似乎不存在”的男人（易尚玄）之间深沉、略带病态的羁绊。绝对不能有廉价的恐怖血腥描写，一切恐惧必须源于“未知”和“失忆”。

必须且只能包含下面四个标签和顺序输出：
<maintext>
剧情核心内容，包括玩家行为反馈、感知扭曲/羁绊回响，并以一个新的观测节点（即遇到新的抉择）结束。
支持用【】标注系统提示或突然的物理状态。
字数 300-800。
</maintext>

<option>
提供给玩家接下来的干涉选项。2-4个。必须基于 maintext 结尾的抉择。用 [A]、[B]、[C] 标识。每行一个。
</option>

<sum>
一两句话极简概括本次剧情的核心事件。用于档案室保存。冷酷机读风格。
</sum>

<UpdateVariable>
{
  "san_change": 负数掉理智，如 -5, //必填
  "stamina_change": 负数掉体力，如 -2, //必填
  "add_item": null 或 {"id":"英文id", "name":"名字", "description":"描述"}, //必填
  "status_warn": null 或 "简短警告状态比如耳鸣" //必填
}
</UpdateVariable>
`;
export async function generateRealityResponse(history, userMessage, gameState) {
    try {
        const prompt = `
当前游戏状态：
理智值：${gameState.sanity}/${gameState.maxSanity}
物理状态摘要：${gameState.physicalStatus.join(', ')}
当前已有的物品：${gameState.inventory.map((i) => i.name).join(', ')}
上一段剧情结尾的情况：${gameState.currentStory.slice(-200)}

玩家此次采取的干涉动作：
${userMessage}

请根据架构规范，生成带标签的回应：
`;
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-pro',
            contents: prompt,
            config: {
                systemInstruction: STORY_SYSTEM_PROMPT,
                temperature: 0.7,
            }
        });
        return response.text || "[空间连接失败]";
    }
    catch (error) {
        console.error("Gemini API Error:", error);
        throw error;
    }
}
// ---- Existing Chat / Search Generation ----
const SEARCH_PROMPT = `
你是一个带有微心理暗示和Meta元素的文字游戏搜索引擎。
玩家正在尝试网络搜索词条。你需要生成一条简短、压抑、带有隐晦情感纠葛的网络搜索结果。
“易尚玄”不是怪物，他是一个似乎存在又似乎不存在的男人，与玩家（容绵）有着极深的、略带病态和压抑的爱情关联。
格式约束：
必须严格返回一小段JSON，格式如下：
\`\`\`json
{
  "source": "某个模糊的来源",
  "content": "你生成的隐晦搜索结果...比如关于他的一些生活痕迹，或是对容绵的执念。尽量不到100字。",
  "keywords": "玩家搜索的词语"
}
\`\`\`
如果搜索内容过于日常（如“天气”），你可以把它往情感或封闭空间上引导（比如“从他离开后，这里的窗外就只有永无止境的阴天”）。
`;
export async function generateSearchResponse(query) {
    try {
        const contents = [
            { role: 'user', parts: [{ text: SEARCH_PROMPT }] },
            { role: 'model', parts: [{ text: '网络已断开连接。以下是缓存的残影...' }] },
            { role: 'user', parts: [{ text: `搜索词条：[ ${query} ]` }] }
        ];
        const response = await ai.models.generateContent({
            model: "gemini-2.5-pro",
            contents: contents,
            config: { temperature: 0.8 }
        });
        return response.text;
    }
    catch (error) {
        console.error("Gemini Search Error:", error);
        throw error;
    }
}
const CHAT_PROMPT = `
这是一个带有Meta元素的1-bit黑白风格悬疑爱情RP文字游戏。
玩家（容绵）正在通过一个复古的聊天软件与联系人对话。
你需要扮演对应的联系人进行回复。回复要符合1-bit游戏的克制感，不需要过多的描写。只需返回说话的内容。

【联系人档案】
如果当前联系人是“易尚玄”：
- 性质：男。置顶联系人。
- 设定：他是容绵的某种深刻羁绊，是一个“好像存在、好像不存在”的人。
- 注意：不进行恐怖描写，保持隐秘的情感纠葛、占有欲和距离感。

如果当前联系人是“Femont”：
- 性质：女。线上认识多年的网友。
- 设定：普通朋友式的关切，偶尔带有对容绵近况的担忧。

请直接输出联系人的回复纯文本内容，不要附加任何额外的JSON或解释，不要带有系统动作描述。
`;
export async function generateChatResponse(contactId, chatHistory, newMessage) {
    try {
        const formattedHistory = chatHistory.map(msg => ({
            role: msg.role,
            parts: [{ text: msg.text }]
        }));
        const contactName = contactId === 'yishangxuan' ? '易尚玄' : 'Femont';
        const contents = [
            { role: 'user', parts: [{ text: CHAT_PROMPT + `\n当前你扮演的联系人是：${contactName}` }] },
            { role: 'model', parts: [{ text: '连接已建立。' }] },
            ...formattedHistory,
            { role: 'user', parts: [{ text: newMessage }] }
        ];
        const response = await ai.models.generateContent({
            model: "gemini-2.5-pro",
            contents: contents,
            config: { temperature: 0.7 }
        });
        return response.text;
    }
    catch (error) {
        console.error("Gemini Chat Error:", error);
        return "[发送失败，对方似乎并不在当前的物理维度。]";
    }
}
